B.aK6=s(["\xa7 4 KSchG","\xa7 7 KSchG"],t.s)
B.RO=new A.hS(B.ko,"Die 3-Wochen-Frist f\xfcr die K\xfcndigungsschutzklage","Der wichtigste Termin \xfcberhaupt \u2013 nach Ablauf gilt die K\xfcndigung als wirksam.",B.a15,B.aK6)
B.Rv=new A.cM("Wann melden?","Wer wei\xdf, dass sein Arbeitsverh\xe4ltnis endet, muss sich sp\xe4testens drei Monate vor dem Ende arbeitsuchend melden. Liegen zwischen Kenntnis und Ende weniger als drei Monate, muss die Meldung innerhalb von drei Tagen nach Kenntnis erfolgen (\xa7 38 SGB III).")
B.Rr=new A.cM("Wie melden?","Die Arbeitsuchendmeldung ist telefonisch, pers\xf6nlich oder online \xfcber die Website der Bundesagentur f\xfcr Arbeit m\xf6glich. Sie ist etwas anderes als die sp\xe4tere Arbeitslosmeldung.")
B.Rs=new A.cM("Warum das wichtig ist","Eine versp\xe4tete Meldung kann als Meldevers\xe4umnis eine Sperrzeit nach sich ziehen (\xa7 159 SGB III) und damit den ALG-Bezug verk\xfcrzen.")
